fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let mut valid: Vec<(String, String)> = Vec::new();

    for i in 0..code.len() {
        let c = code[i].clone();
        let bl = businessLine[i].clone();
        let active = isActive[i];

        if !c.is_empty() {
            let mut valid_code = true;
            for ch in c.chars() {
                if !ch.is_alphanumeric() && ch != '_' {
                    valid_code = false;
                    break;
                }
            }
            if valid_code {
                if ["electronics", "grocery", "pharmacy", "restaurant"].contains(&bl.as_str()) {
                    if active {
                        valid.push( (c, bl) );
                    }
                }
            }
        }
    }

    let business_order = ["electronics", "grocery", "pharmacy", "restaurant"];
    valid.sort_by(|a, b| {
        let idx_a = business_order.iter().position(|x| x == &a.1).unwrap();
        let idx_b = business_order.iter().position(|x| x == &b.1).unwrap();
        if idx_a != idx_b {
            idx_a.cmp(&idx_b)
        } else {
            a.0.cmp(&b.0)
        }
    });

    valid.iter().map(|x| x.0.clone()).collect()
}
