    valid.sort_by(|a, b| {
        let idx_a = business_order.iter().position(|x| x == &a.1).unwrap();
        let idx_b = business_order.iter().position(|x| x == &b.1).unwrap();
        if idx_a != idx_b {
            idx_a.cmp(&idx_b)
        } else {
            a.0.cmp(&b.0)
        }
    });

    valid.into_iter().map(|x| x.0).collect()
}
