```typescript
function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
  const validCoupons: { code: string; businessLine: string }[] = [];

  for (let i = 0; i < code.length; i++) {
    const c = code[i];
    const bl = businessLine[i];
    const active = isActive[i];

    if (c && c.match(/^[a-zA-Z0-9_]+$/)) {
      if (['electronics', 'grocery', 'pharmacy', 'restaurant'].includes(bl)) {
        if (active) {
          validCoupons.push({ code: c, businessLine: bl });
        }
      }
    }
  }

  const businessOrder = ["electronics", "grocery", "pharmacy", "restaurant"];
  validCoupons.sort((a, b) => {
    const idxA = businessOrder.indexOf(a.businessLine);
    const idxB = businessOrder.indexOf(b.businessLine);
    if (idxA !== idxB) return idxA - idxB;
    return a.code.localeCompare(b.code);
  });

  return validCoupons.map(c => c.code);
}
```

